+    }
+    Ok(u64::try_from(value).unwrap_or(u64::MAX))
+}
+
+fn opt_i64_to_u64_non_negative(
+    value: Option<i64>,
+    field: &str,
+) -> frankensearch_core::SearchResult<Option<u64>> {
+    value
+        .map(|raw| i64_to_u64_non_negative(raw, field))
